import React, { useState } from 'react';
import { Target, AlertCircle, CheckCircle } from 'lucide-react';

const BudgetSettings = () => {
  const [budgets, setBudgets] = useState({
    monthly: 3000,
    food: 500,
    transport: 300,
    entertainment: 200,
    shopping: 400
  });

  const [actualSpending, setActualSpending] = useState({
    food: 320,
    transport: 280,
    entertainment: 150,
    shopping: 350
  });

  const handleBudgetChange = (category, value) => {
    setBudgets(prev => ({
      ...prev,
      [category]: parseFloat(value) || 0
    }));
  };

  const getBudgetStatus = (category) => {
    const spent = actualSpending[category] || 0;
    const budget = budgets[category] || 0;
    const percentage = budget > 0 ? (spent / budget) * 100 : 0;
    
    if (percentage >= 90) return 'over';
    if (percentage >= 75) return 'warning';
    return 'good';
  };

  return (
    <div className="budget-settings">
      <div className="page-header">
        <h1><Target size={24} /> Budget Settings</h1>
      </div>
      
      <table className="budget-settings-table">
        <thead>
          <tr>
            <th>Category</th>
            <th>Budget</th>
            <th>Spent</th>
            <th>Percentage</th>
            <th>Status</th>
          </tr>
        </thead>
        <tbody>
          <tr>
            <td className="budget-category">Food</td>
            <td className="budget-amount">${budgets.food}</td>
            <td className="budget-spent">${actualSpending.food}</td>
            <td>
              <span className={`budget-percentage ${getBudgetStatus('food')}`}>
                {budgets.food > 0 ? ((actualSpending.food / budgets.food) * 100).toFixed(1) : 0}%
              </span>
            </td>
            <td className="budget-status">
              {getBudgetStatus('food') === 'over' && 'Over budget!'}
            </td>
          </tr>
          <tr>
            <td className="budget-category">Transport</td>
            <td className="budget-amount">${budgets.transport}</td>
            <td className="budget-spent">${actualSpending.transport}</td>
            <td>
              <span className={`budget-percentage ${getBudgetStatus('transport')}`}>
                {budgets.transport > 0 ? ((actualSpending.transport / budgets.transport) * 100).toFixed(1) : 0}%
              </span>
            </td>
            <td className="budget-status">
              {getBudgetStatus('transport') === 'over' && 'Over budget!'}
            </td>
          </tr>
          <tr>
            <td className="budget-category">Entertainment</td>
            <td className="budget-amount">${budgets.entertainment}</td>
            <td className="budget-spent">${actualSpending.entertainment}</td>
            <td>
              <span className={`budget-percentage ${getBudgetStatus('entertainment')}`}>
                {budgets.entertainment > 0 ? ((actualSpending.entertainment / budgets.entertainment) * 100).toFixed(1) : 0}%
              </span>
            </td>
            <td className="budget-status">
              {getBudgetStatus('entertainment') === 'over' && 'Over budget!'}
            </td>
          </tr>
          <tr>
            <td className="budget-category">Shopping</td>
            <td className="budget-amount">${budgets.shopping}</td>
            <td className="budget-spent">${actualSpending.shopping}</td>
            <td>
              <span className={`budget-percentage ${getBudgetStatus('shopping')}`}>
                {budgets.shopping > 0 ? ((actualSpending.shopping / budgets.shopping) * 100).toFixed(1) : 0}%
              </span>
            </td>
            <td className="budget-status">
              {getBudgetStatus('shopping') === 'over' && 'Over budget!'}
            </td>
          </tr>
        </tbody>
      </table>
    </div>
  );
};

export default BudgetSettings;
